def solve_n_queens(n):
    def is_safe(board, row, col):
        for i in range(row):
            if board[i] == col or \
               board[i] - i == col - row or \
               board[i] + i == col + row:
                return False
        return True

    def solve(board, row):
        if row == n: return 1
        count = 0
        for col in range(n):
            if is_safe(board, row, col):
                board[row] = col
                count += solve(board, row + 1)
                board[row] = -1
        return count

    board = [-1] * n
    return solve(board, 0)

print(f'10-Queens solutions: {solve_n_queens(10)}')

def solve(board):
    empty = find_empty(board)
    if not empty: return True
    r, c = empty
    for i in range(1, 10):
        if valid(board, i, (r, c)):
            board[r][c] = i
            if solve(board): return True
            board[r][c] = 0
    return False

def valid(board, num, pos):
    for i in range(len(board[0])):
        if board[pos[0]][i] == num and pos[1] != i: return False
    for i in range(len(board)):
        if board[i][pos[1]] == num and pos[0] != i: return False
    bx, by = pos[1] // 3, pos[0] // 3
    for i in range(by * 3, by * 3 + 3):
        for j in range(bx * 3, bx * 3 + 3):
            if board[i][j] == num and (i, j) != pos: return False
    return True

def find_empty(board):
    for i in range(len(board)):
        for j in range(len(board[0])):
            if board[i][j] == 0: return (i, j)
    return None

