def rror(val, r_bits, max_bits=32):
    return ((val & (2**max_bits-1)) >> r_bits) | (val << (max_bits - r_bits) & (2**max_bits-1))

# Extremely simplified mock of bitwise mixing to test runtime bitops
def mix_bits(s, rounds=1000):
    state = [0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a]
    for _ in range(rounds):
        for char in s:
            v = ord(char)
            s1 = rror(state[0], 2) ^ rror(state[1], 13) ^ rror(state[2], 22)
            ch = (state[0] & state[1]) ^ (~state[0] & state[2])
            temp1 = (state[3] + s1 + ch + v) & 0xFFFFFFFF
            state[3] = state[2]
            state[2] = state[1]
            state[1] = state[0]
            state[0] = temp1
    return ''.join(f'{x:08x}' for x in state)

