def match(pattern, text):
    def match_here(p, t):
        if not p:
            return True
        if len(p) > 1 and p[1] == '*':
            return match_star(p[0], p[2:], t)
        if len(p) > 1 and p[1] == '+':
            if not t or (p[0] != '.' and t[0] != p[0]):
                return False
            return match_star(p[0], p[2:], t[1:])
        if not t:
            return False
        if p[0] == '.' or p[0] == t[0]:
            return match_here(p[1:], t[1:])
        return False

    def match_star(c, p, t):
        while True:
            if match_here(p, t):
                return True
            if not t or (c != '.' and t[0] != c):
                return False
            t = t[1:]

    if pattern.startswith('^'):
        return match_here(pattern[1:], text)
    while True:
        if match_here(pattern, text):
            return True
        if not text:
            return False
        text = text[1:]

